/* token.h -- Token types and keyword table for PL/SW lexer */

#ifndef TOKEN_H
#define TOKEN_H

#include "str.h"

/* Token type codes */
#define TOK_DCL       1
#define TOK_DECLARE   2
#define TOK_PROC      3
#define TOK_IF        4
#define TOK_THEN      5
#define TOK_ELSE      6
#define TOK_DO        7
#define TOK_WHILE     8
#define TOK_END       9
#define TOK_CALL      10
#define TOK_RETURN    11
#define TOK_ASM       12
#define TOK_STATIC    13
#define TOK_AUTO      14
#define TOK_EXTERNAL  15
#define TOK_INT       16
