/* Returns 1 if equal, 0 otherwise */
int str_eq(char *a, char *b) {
    while (*a && *b && *a == *b) {
        a = a + 1;
        b = b + 1;
    }
    return *a == *b;
}

/* Find substring needle in haystack. Returns pointer to first match, or 0. */
char *str_find(char *haystack, char *needle) {
    char *h;
    char *n;
    char *start;

    if (!*needle) return haystack;

    start = haystack;
    while (*start) {
        h = start;
        n = needle;
        while (*h && *n && *h == *n) {
            h = h + 1;
            n = n + 1;
        }
        if (!*n) return start;
        start = start + 1;
    }
    return 0;
}

