    /* Test 1: init and insert at global scope */
    uart_puts("--- global scope ---");
    arena_init();
    sym_init();

    idx = sym_insert("COUNT", TYPE_INT24, 3, STOR_AUTO);
    uart_putstr("insert COUNT: idx=");
