    test_type_compat("none->int", TYPE_NONE, TYPE_INT24, 1);
    test_type_compat("rec->int", TYPE_RECORD, TYPE_INT24, 0);
    test_type_compat("arr->int", TYPE_ARRAY, TYPE_INT24, 0);

