        asgn = nd_assign(nd_ident("X"), outer);
        cg_assign(asgn);
    }
    uart_putstr(emit_output());
    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

    /* Test 7: Multiple assignments (X=10, Y=20, Z=X+Y pattern) */
    uart_puts("--- asgn: multi ---");
