    /* Y = 20 */
    cg_assign(nd_assign(nd_ident("Y"), nd_literal(20)));
    /* Z = X + Y */
    cg_assign(nd_assign(nd_ident("Z"), nd_binop(TOK_PLUS, nd_ident("X"), nd_ident("Y"))));
    uart_putstr(emit_output());
    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

