        fsize = layout_proc(proc);
        uart_putstr("  frame_size=");
        print_int(fsize);
        uart_putchar(10);

        idx = sym_lookup("COUNTER");
        uart_putstr("  COUNTER(static): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        idx = sym_lookup("LOCAL");
        uart_putstr("  LOCAL(auto): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        layout_print_frame();
        sym_exit_scope();
    } else {
